// Rise 6.0 - BlockESP (S23 handling):
@EventTarget
public void onPacketReceive(EventReceivePacket event) {
    if (event.getPacket() instanceof S23PacketBlockChange) {
        S23PacketBlockChange s23 = (S23PacketBlockChange) event.getPacket();
        BlockPos pos = s23.getBlockPosition();
        int state = s23.getBlockState();
        int blockId = state & 0xFFF;

        if (blockId == 26) { // bed
            bedPositions.add(pos);
        }
        if (blockId == 54 || blockId == 146) { // chest / trapped
            chestPositions.add(pos);
        }
        if (blockId == 56) { // diamond ore
            orePositions.add(pos);
        }
        if (blockId == 0) { // air — block removed
            bedPositions.remove(pos);
            chestPositions.remove(pos);
        }
    }
}

