package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import net.minecraft.util.BlockPos;
import java.io.IOException;

public class S23PacketBlockChange implements Packet<INetHandlerPlayClient> {
    private BlockPos blockPosition;
    private int blockState;

    public S23PacketBlockChange() {}
    public S23PacketBlockChange(BlockPos posIn, int stateIn) {
        this.blockPosition = posIn;
        this.blockState = stateIn;
    }

    public void processPacket(INetHandlerPlayClient handler) { handler.handleBlockChange(this); }
    public BlockPos getBlockPosition() { return this.blockPosition; }
    public int getBlockState() { return this.blockState; }
}

